    pub(super) async fn create_compute_address(
        &self,
        config: &serde_json::Value,
    ) -> Result<ResourceOutput, ProviderError> {
        // Extract fields from config
        let address = config.optional_str("/config/address").map(String::from);
        let address_type = config
            .optional_str("/config/address_type")
            .map(String::from);
        let description = config
            .optional_str("/identity/description")
            .map(String::from);
        let ip_collection = config
            .optional_str("/config/ip_collection")
            .map(String::from);
        let ip_version = config.optional_str("/config/ip_version").map(String::from);
        let ipv_6_endpoint_type = config
            .optional_str("/config/ipv_6_endpoint_type")
            .map(String::from);
        let _labels_val = config
            .pointer("/identity/labels")
            .and_then(|v| serde_json::from_value::<HashMap<String, String>>(v.clone()).ok());
        let name = config.require_str("/identity/name")?.to_string();
        let network = config.optional_str("/network/network").map(String::from);
        let network_tier = config
            .optional_str("/config/network_tier")
            .map(String::from);
        let prefix_length = config.optional_i64("/config/prefix_length");
        let purpose = config.optional_str("/config/purpose").map(String::from);
        let subnetwork = config.optional_str("/network/subnetwork").map(String::from);

        let labels = super::extract_labels(config);
        // Build SDK model
        let mut model = google_cloud_compute_v1::model::Address::default();
        if let Some(v) = address {
            model = model.set_address(v);
        }
        if let Some(ref s) = address_type {
            model = model.set_address_type(
                google_cloud_compute_v1::model::address::AddressType::from(s.as_str()),
            );
        }
        if let Some(v) = description {
            model = model.set_description(v);
        }
        if let Some(v) = ip_collection {
            model = model.set_ip_collection(v);
        }
        if let Some(ref s) = ip_version {
            model = model.set_ip_version(google_cloud_compute_v1::model::address::IpVersion::from(
                s.as_str(),
            ));
        }
        if let Some(ref s) = ipv_6_endpoint_type {
            model = model.set_ipv_6_endpoint_type(
                google_cloud_compute_v1::model::address::Ipv6EndpointType::from(s.as_str()),
            );
        }
        model = model.set_name(name.clone());
        if let Some(v) = network {
            model = model.set_network(v);
        }
        if let Some(ref s) = network_tier {
            model = model.set_network_tier(
                google_cloud_compute_v1::model::address::NetworkTier::from(s.as_str()),
            );
        }
        if let Some(v) = prefix_length {
            model = model.set_prefix_length(i32::try_from(v).map_err(|_| {
                ProviderError::InvalidConfig(format!(
                    "prefix_length: value {v} out of range for i32"
                ))
            })?);
        }
        if let Some(ref s) = purpose {
            model = model.set_purpose(google_cloud_compute_v1::model::address::Purpose::from(
                s.as_str(),
            ));
        }
        if let Some(v) = subnetwork {
            model = model.set_subnetwork(v);
        }
        model = model.set_labels(labels);

        // Make API call
        let region = config.str_or("/network/region", &self.region).to_string();
        self.addresses()
            .await?
            .insert()
            .set_project(&self.project_id)
            .set_region(&region)
            .set_body(model)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("Insert Address", e))?;

        let provider_id = format!("{region}/{name}");
        self.read_compute_address(&provider_id).await
    }

    pub(super) async fn read_compute_address(
        &self,
        provider_id: &str,
    ) -> Result<ResourceOutput, ProviderError> {
        let (region, name) = super::parse_region_resource(provider_id, &self.region);
        let address = self
            .addresses()
            .await?
            .get()
            .set_project(&self.project_id)
            .set_region(&region)
            .set_address(&name)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("GetAddress", e))?;

        let mut state = serde_json::json!({
            "identity": {
                "name": address.name.as_deref().unwrap_or(""),
            },
        });

        // identity: optional fields
        if let Some(desc) = address.description.as_deref().filter(|s| !s.is_empty()) {
            state["identity"]["description"] = serde_json::json!(desc);
        }
        let user_labels: serde_json::Map<String, serde_json::Value> = address
            .labels
            .iter()
            .filter(|(k, _)| k.as_str() != "managed_by")
            .map(|(k, v)| (k.clone(), serde_json::json!(v)))
            .collect();
        if !user_labels.is_empty() {
            state["identity"]["labels"] = serde_json::json!(user_labels);
        }

        // config: only include user-facing fields that are non-empty/non-default
        // Note: `address` (the IP) is server-assigned and goes in outputs, not config
        let mut config = serde_json::Map::new();
        if let Some(at) = address.address_type.as_ref().and_then(|e| e.name()) {
            if at != "EXTERNAL" {
                config.insert("address_type".into(), serde_json::json!(at));
            }
        }
        if let Some(ip_ver) = address.ip_version.as_ref().and_then(|e| e.name()) {
            config.insert("ip_version".into(), serde_json::json!(ip_ver));
        }
        if let Some(net_tier) = address.network_tier.as_ref().and_then(|e| e.name()) {
            if net_tier != "PREMIUM" {
                config.insert("network_tier".into(), serde_json::json!(net_tier));
            }
        }
        if let Some(purpose) = address.purpose.as_ref().and_then(|e| e.name()) {
            config.insert("purpose".into(), serde_json::json!(purpose));
        }
        if !config.is_empty() {
            state["config"] = serde_json::Value::Object(config);
        }

        // network: skip empty strings
        let mut network = serde_json::Map::new();
        if let Some(net) = address.network.as_deref().filter(|s| !s.is_empty()) {
            network.insert(
                "network".into(),
                serde_json::json!(super::normalize_gcp_url(net)),
            );
        }
        if let Some(sub) = address.subnetwork.as_deref().filter(|s| !s.is_empty()) {
            network.insert(
                "subnetwork".into(),
                serde_json::json!(super::normalize_gcp_url(sub)),
            );
        }
        if !network.is_empty() {
            state["network"] = serde_json::Value::Object(network);
        }

        let mut outputs = HashMap::new();
        outputs.insert(
            "self_link".into(),
            serde_json::json!(address.self_link.as_deref().unwrap_or("")),
        );
        if let Some(addr) = address.address.as_deref().filter(|s| !s.is_empty()) {
            outputs.insert("address".into(), serde_json::json!(addr));
        }

        Ok(ResourceOutput {
            provider_id: provider_id.to_string(),
            state,
            outputs,
        })
    }

    pub(super) async fn update_compute_address(
        &self,
        _provider_id: &str,
        _config: &serde_json::Value,
    ) -> Result<ResourceOutput, ProviderError> {
        Err(ProviderError::RequiresReplacement(
            "resource does not support in-place update".into(),
        ))
    }

    pub(super) async fn delete_compute_address(
        &self,
        provider_id: &str,
    ) -> Result<(), ProviderError> {
        let (region, name) = super::parse_region_resource(provider_id, &self.region);
        self.addresses()
            .await?
            .delete()
            .set_project(&self.project_id)
            .set_region(&region)
            .set_address(&name)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("DeleteAddress", e))?;
        Ok(())
    }

