    pub(super) async fn delete_compute_disk(&self, provider_id: &str) -> Result<(), ProviderError> {
        let (zone, name) = super::parse_zone_resource(provider_id, &self.region);
        self.disks()
            .await?
            .delete()
            .set_project(&self.project_id)
            .set_zone(&zone)
            .set_disk(&name)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("DeleteDisk", e))?;
        Ok(())
    }

