    pub(super) async fn create_compute_route(
        &self,
        config: &serde_json::Value,
    ) -> Result<ResourceOutput, ProviderError> {
        // Extract fields from config
        let description = config
            .optional_str("/identity/description")
            .map(String::from);
        let dest_range = config.optional_str("/config/dest_range").map(String::from);
        let name = config.require_str("/identity/name")?.to_string();
        let network = config.optional_str("/network/network").map(String::from);
        let next_hop_gateway = config
            .optional_str("/config/next_hop_gateway")
            .map(String::from);
        let next_hop_ilb = config
            .optional_str("/config/next_hop_ilb")
            .map(String::from);
        let next_hop_instance = config
            .optional_str("/config/next_hop_instance")
            .map(String::from);
        let next_hop_ip = config.optional_str("/config/next_hop_ip").map(String::from);
        let next_hop_network = config
            .optional_str("/config/next_hop_network")
            .map(String::from);
        let next_hop_vpn_tunnel = config
            .optional_str("/config/next_hop_vpn_tunnel")
            .map(String::from);
        let params = config.pointer("/config/params").and_then(|v| {
            serde_json::from_value::<google_cloud_compute_v1::model::RouteParams>(v.clone()).ok()
        });
        let priority = config.optional_i64("/security/priority");
        let tags = config
            .pointer("/identity/tags")
            .and_then(|v| serde_json::from_value::<Vec<String>>(v.clone()).ok());

        // Build SDK model
        let mut model = google_cloud_compute_v1::model::Route::default();
        if let Some(v) = description {
            model = model.set_description(v);
        }
        if let Some(v) = dest_range {
            model = model.set_dest_range(v);
        }
        model = model.set_name(name.clone());
        if let Some(v) = network {
            model = model.set_network(v);
        }
        if let Some(v) = next_hop_gateway {
            model = model.set_next_hop_gateway(v);
        }
        if let Some(v) = next_hop_ilb {
            model = model.set_next_hop_ilb(v);
        }
        if let Some(v) = next_hop_instance {
            model = model.set_next_hop_instance(v);
        }
        if let Some(v) = next_hop_ip {
            model = model.set_next_hop_ip(v);
        }
        if let Some(v) = next_hop_network {
            model = model.set_next_hop_network(v);
        }
        if let Some(v) = next_hop_vpn_tunnel {
            model = model.set_next_hop_vpn_tunnel(v);
        }
        if let Some(v) = params {
            model = model.set_params(v);
        }
        if let Some(v) = priority {
            model = model.set_priority(u32::try_from(v).map_err(|_| {
                ProviderError::InvalidConfig(format!("priority: value {v} out of range for u32"))
            })?);
        }
        if let Some(v) = tags {
            model = model.set_tags(v);
        }

        // Make API call
        self.routes()
            .await?
            .insert()
            .set_project(&self.project_id)
            .set_body(model)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("Insert Route", e))?;

        let provider_id = name.to_string();
        self.read_compute_route(&provider_id).await
    }

    pub(super) async fn read_compute_route(
        &self,
        provider_id: &str,
    ) -> Result<ResourceOutput, ProviderError> {
        let name = provider_id.to_string();
        let route = self
            .routes()
            .await?
            .get()
            .set_project(&self.project_id)
            .set_route(&name)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("GetRoute", e))?;

        let mut state = serde_json::json!({
            "identity": {
                "name": route.name.as_deref().unwrap_or(""),
            },
        });

        // identity: optional fields
        if let Some(desc) = route.description.as_deref().filter(|s| !s.is_empty()) {
            state["identity"]["description"] = serde_json::json!(desc);
        }
        if !route.tags.is_empty() {
            state["identity"]["tags"] = serde_json::json!(&route.tags);
        }

        // config: only include non-empty fields, strip URLs
        let mut config = serde_json::Map::new();
        if let Some(dr) = route.dest_range.as_deref().filter(|s| !s.is_empty()) {
            config.insert("dest_range".into(), serde_json::json!(dr));
        }
        if let Some(nhg) = route.next_hop_gateway.as_deref().filter(|s| !s.is_empty()) {
            config.insert(
                "next_hop_gateway".into(),
                serde_json::json!(super::normalize_gcp_url(nhg)),
            );
        }
        if let Some(nhi) = route.next_hop_ilb.as_deref().filter(|s| !s.is_empty()) {
            config.insert(
                "next_hop_ilb".into(),
                serde_json::json!(super::normalize_gcp_url(nhi)),
            );
        }
        if let Some(nhi) = route.next_hop_instance.as_deref().filter(|s| !s.is_empty()) {
            config.insert(
                "next_hop_instance".into(),
                serde_json::json!(super::normalize_gcp_url(nhi)),
            );
        }
        if let Some(nhip) = route.next_hop_ip.as_deref().filter(|s| !s.is_empty()) {
            config.insert("next_hop_ip".into(), serde_json::json!(nhip));
        }
        if let Some(nhn) = route.next_hop_network.as_deref().filter(|s| !s.is_empty()) {
            config.insert(
                "next_hop_network".into(),
                serde_json::json!(super::normalize_gcp_url(nhn)),
            );
        }
        if let Some(nhv) = route
            .next_hop_vpn_tunnel
            .as_deref()
            .filter(|s| !s.is_empty())
        {
            config.insert(
                "next_hop_vpn_tunnel".into(),
                serde_json::json!(super::normalize_gcp_url(nhv)),
            );
        }
        if !config.is_empty() {
            state["config"] = serde_json::Value::Object(config);
        }

        // network: strip URL to short form
        if let Some(net) = route.network.as_deref().filter(|s| !s.is_empty()) {
            state["network"] = serde_json::json!({ "network": super::normalize_gcp_url(net) });
        }

        // security: skip default priority (1000)
        if let Some(p) = route.priority {
            if p != 1000 {
                state["security"] = serde_json::json!({ "priority": p });
            }
        }

        let mut outputs = HashMap::new();
        outputs.insert(
            "self_link".into(),
            serde_json::json!(route.self_link.as_deref().unwrap_or("")),
        );

        Ok(ResourceOutput {
            provider_id: provider_id.to_string(),
            state,
            outputs,
        })
    }

