    pub(super) async fn create_compute_securitypolicy(
        &self,
        config: &serde_json::Value,
    ) -> Result<ResourceOutput, ProviderError> {
        // Extract fields from config
        let associations = config.pointer("/config/associations").and_then(|v| {
            serde_json::from_value::<
                    Vec<google_cloud_compute_v1::model::SecurityPolicyAssociation>,
                >(v.clone())
                .ok()
        });
        let description = config
            .optional_str("/identity/description")
            .map(String::from);
        let _labels_val = config
            .pointer("/identity/labels")
            .and_then(|v| serde_json::from_value::<HashMap<String, String>>(v.clone()).ok());
        let name = config.require_str("/identity/name")?.to_string();
        let rules = config.pointer("/config/rules").and_then(|v| {
            serde_json::from_value::<Vec<google_cloud_compute_v1::model::SecurityPolicyRule>>(
                v.clone(),
            )
            .ok()
        });
        let short_name = config.optional_str("/config/short_name").map(String::from);
        let type_val = config.optional_str("/config/type").map(String::from);
        let user_defined_fields = config.pointer("/config/user_defined_fields").and_then(|v| {
            serde_json::from_value::<
                Vec<google_cloud_compute_v1::model::SecurityPolicyUserDefinedField>,
            >(v.clone())
            .ok()
        });

        let labels = super::extract_labels(config);
        // Build SDK model
        let mut model = google_cloud_compute_v1::model::SecurityPolicy::default();
        if let Some(v) = associations {
            model = model.set_associations(v);
        }
        if let Some(v) = description {
            model = model.set_description(v);
        }
        model = model.set_name(name.clone());
        if let Some(v) = rules {
            model = model.set_rules(v);
        }
        if let Some(v) = short_name {
            model = model.set_short_name(v);
        }
        if let Some(ref s) = type_val {
            model = model.set_type(google_cloud_compute_v1::model::security_policy::Type::from(
                s.as_str(),
            ));
        }
        if let Some(v) = user_defined_fields {
            model = model.set_user_defined_fields(v);
        }
        model = model.set_labels(labels);

        // Make API call
        self.security_policies()
            .await?
            .insert()
            .set_project(&self.project_id)
            .set_body(model)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("Insert SecurityPolicy", e))?;

        let provider_id = name.to_string();
        self.read_compute_securitypolicy(&provider_id).await
    }

    pub(super) async fn read_compute_securitypolicy(
        &self,
        provider_id: &str,
    ) -> Result<ResourceOutput, ProviderError> {
        let name = provider_id.to_string();
        let security_policy = self
            .security_policies()
            .await?
            .get()
            .set_project(&self.project_id)
            .set_security_policy(&name)
            .send()
            .await
            .map_err(|e| super::classify_gcp_error("GetSecurityPolicy", e))?;

        let user_labels: serde_json::Map<String, serde_json::Value> = security_policy
            .labels
            .iter()
            .filter(|(k, _)| k.as_str() != "managed_by")
            .map(|(k, v)| (k.clone(), serde_json::json!(v)))
            .collect();

        let mut state = serde_json::json!({
            "identity": {
                "name": security_policy.name.as_deref().unwrap_or(""),
            },
        });
        // Conditionally include optional fields — skip server-generated defaults
        if let Some(desc) = security_policy
            .description
            .as_deref()
            .filter(|s| !s.is_empty())
        {
            state["identity"]["description"] = serde_json::json!(desc);
        }
        if !user_labels.is_empty() {
            state["identity"]["labels"] = serde_json::Value::Object(user_labels);
        }
        // Skip: rules (server-generated default rule), type (server-set "CLOUD_ARMOR"),
        // associations (server-managed). Only include user_defined_fields and short_name
        // if they have meaningful content.
        state["config"] = serde_json::json!({});
        if let Some(sn) = security_policy
            .short_name
            .as_deref()
            .filter(|s| !s.is_empty())
        {
            state["config"]["short_name"] = serde_json::json!(sn);
        }
        if !security_policy.user_defined_fields.is_empty() {
            state["config"]["user_defined_fields"] =
                serde_json::json!(&security_policy.user_defined_fields);
        }

        let mut outputs = HashMap::new();
        outputs.insert(
            "self_link".into(),
            serde_json::json!(security_policy.self_link.as_deref().unwrap_or("")),
        );

        Ok(ResourceOutput {
            provider_id: provider_id.to_string(),
            state,
            outputs,
        })
    }

